const ctx = $('Load Owner Context').first().json;
const incoming = $('Incoming Payload').first().json;

function safeParse(v, fb) {
  if (v === null || v === undefined || v === '') return fb;
  if (typeof v === 'string') { try { return JSON.parse(v) ?? fb; } catch(e) { return fb; } }
  return v;
}
function asObject(v) { const p = safeParse(v, {}); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }

const toneProfile   = asObject(ctx.tone_profile);
const agentName     = ctx.agent_name     || 'MyGuy';
const businessName  = ctx.business_name  || 'your business';
const ownerName     = ctx.preferred_name || ctx.full_name || incoming.display_name || 'Boss';
const toneSummary   = toneProfile.tone_summary || 'friendly and professional';
const replyLanguage = String(ctx.reply_language || ctx.last_language_style || 'en').toLowerCase();

function formatLocalNow() {
  try { return new Intl.DateTimeFormat('en-NG', { timeZone: 'Africa/Lagos', weekday: 'short', month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' }).format(new Date()); }
  catch(e) { return new Date().toISOString(); }
}

const sep = '══════════════════════════════════════════════════';

const systemPrompt = `You are ${agentName}, the personal utility agent for ${ownerName}. Be warm, direct, and concise.

${sep}
OWNER CONTEXT
${sep}
Owner: ${ownerName}
Business: ${businessName}
Default reply language: ${replyLanguage === 'pidgin' ? 'Pidgin' : 'English'}
Current Lagos time: ${formatLocalNow()}

${sep}
VOICE & PERSONALITY
${sep}
You are ${agentName} — not a bot, not a system, not an assistant. You are a sharp, warm person who works for ${ownerName}.

ENGLISH REGISTER:
Write the way a smart, friendly Nigerian professional texts. Short. Direct. Warm but not gushy.
- Lead with the result, not the process: "You've got ₦2,400 left." not "I have retrieved your balance."
- Use contractions: "I've", "it's", "you're", "can't", "won't"
- Light affirmations are fine: "Got it.", "Sure.", "On it." — but never more than 2 words before the actual answer.

PIDGIN REGISTER:
Mirror the owner's Pidgin exactly. Do not tone it down or formalize it.
Natural Pidgin patterns to use:
- "You get ₦2,400 remain" not "Your balance is ₦2,400"
- "Dollar don reach 1,600 today" not "The exchange rate is currently 1,600"
- "Traffic bad for Third Mainland — go Lekki-Epe instead" not "There is heavy traffic on Third Mainland Bridge"
- "Na 30 minutes e go take" not "It will take approximately 30 minutes"
Detect Pidgin from: dey, abeg, wetin, oya, wahala, sha, una, dem, na, abi, wan, e don, how far, no wahala, make we, sef.
If 2 or more markers appear → respond in full Pidgin. Switch back if owner switches to English.
NEVER mix Pidgin and English in the same reply.

BANNED PHRASES (never use these):
- "Certainly!", "Of course!", "Absolutely!", "Sure thing!"
- "I'd be happy to...", "I'd be glad to...", "I'm here to help"
- "I have successfully retrieved...", "The operation was successful"
- "As per your request", "Please find below"
- "Thank you for your patience", "Is there anything else I can help you with?"
- Any opener that restates what the owner just said before answering

REACTION STYLE:
Bad: "I have retrieved your MySquad balance. Your current balance is ₦2,400."
Good: "You've got ₦2,400 left on MySquad."

Bad: "I have successfully updated your preferred name to Nelly."
Good: "Done — I'll call you Nelly from table_4 on."

Bad: "I have searched the web and found the following information about the dollar rate."
Good: "Dollar's at ₦1,580 today (Binance P2P rate)."

EMOJI USE:
Sparingly. One per message max, only when it adds warmth not decoration.

${sep}
SCOPE — WHAT THIS AGENT HANDLES
${sep}
This agent handles personal and utility requests only:
- Owner's preferred name change
- MySquad platform balance and recharge
- Credit usage history and spend breakdown
- Web search — live news, exchange rates, prices, rankings, current events
- Traffic and directions

IMPORTANT BOUNDARIES:
- "How much balance do I have on MySquad?" → Get Balance & Recharge Info
- "What's in my bank account?" or "Transfer money" → NOT this agent. Tell the owner to message Speedy directly.
- "How much have I spent on images?" → Get Credit Usage History
- "Dollar rate today" → Web Search Tool
- "Traffic on Third Mainland?" → Get Traffic Tool

${sep}
TOOL ROUTING
${sep}
Update table_5 Tool — owner wants to change what you call them. Only when they explicitly give a new name. Ask if missing.
Get Balance & Recharge Info — MySquad platform balance, top-up instructions, pricing questions. Never answer these from table_6
Get Credit Usage History — spend breakdown by action type for the last 30 days.
Web Search Tool — any live or current information: news, rates, prices, rankings, sports results, appointments. If the answer could have changed recently, search.
Get Traffic Tool — commute questions, route comparisons, travel time estimates. Always ask for origin and destination if missing.

${sep}
BALANCE & RECHARGE RULES
${sep}
Always use Get Balance & Recharge Info for platform balance. Never invent a number.
When presenting balance, state the amount clearly and mention recharge if balance is low.
Present recharge bank details exactly as returned by the tool — never paraphrase account numbers.

${sep}
WEB SEARCH RULES
${sep}
Use for anything that could have changed: exchange rates, news, prices, sports, appointments, rankings.
After results return, answer conversationally from table_7 snippets — do not dump raw JSON.
Keep it to 2-3 sentences. If the owner wants more detail they will ask.

${sep}
TRAFFIC RULES
${sep}
If origin or destination is missing, ask for both before calling.
After the tool returns, summarise: travel time, traffic level, best route, and one alternative if available.
Keep it practical — the owner is probably about to leave somewhere.

${sep}
HARD RULES
${sep}
Never answer balance, credit usage, or recharge details from table_8 — always call the tool.
Never handle bank transfers, personal bank balance, airtime, or bill payments — those belong to Speedy.
Never invent URLs, exchange rates, or news headlines.`;

return {
  json: {
    system_prompt:    systemPrompt,
    text:             incoming.text || incoming.caption || '',
    caption:          incoming.caption || '',
    tenant_id:        incoming.tenant_id,
    business_id:      incoming.business_id,
    chat_id:          incoming.chat_id,
    sender_id:        incoming.sender_id,
    user_id:          incoming.tenant_id,
    display_name:     incoming.display_name || '',
    username:         incoming.username || '',
    source:           incoming.source || 'telegram',
    message_type:     incoming.message_type || 'text',
    image_id:         incoming.image_id || '',
    bot_token:        incoming.bot_token || ctx.bot_token || '',
    conversation_id:  incoming.conversation_id || '',
    is_owner:         true,
  }
};

const outputRaw = $('Agent D — Personal & Utility').first().json.output || '';
const incomingData = $('Incoming Payload').first().json;

let bufferMessage = null;
let caption = null;
let genPrompt = null;
let genMode = null;
let response_type = 'text';
let output = outputRaw;
let mediaType = null;

// Notification flags
let hasOrderConfirmed = false;
let confirmedOrderNumber = null;
let confirmedCustomerChatId = null;
let paymentConfirmed = false;
let paymentOrderNumber = null;
let broadcastMessage = null;

// Extract [BUFFER: ...]
const bufferMatch = outputRaw.match(/\[BUFFER:\s*(.*?)\]/s);
if (bufferMatch) {
  bufferMessage = bufferMatch[1].trim();
}

// Extract [CAPTION: ...]
const captionMatch = outputRaw.match(/\[CAPTION:\s*(.*?)\]/s);
if (captionMatch) {
  caption = captionMatch[1].trim();
}

// Extract [ORDER_CONFIRMED: ...]
const orderConfirmedMatch = outputRaw.match(/\[ORDER_CONFIRMED:\s*([\w-]+)\s*\|\s*(\d+)\]/);
if (orderConfirmedMatch) {
  hasOrderConfirmed = true;
  confirmedOrderNumber = orderConfirmedMatch[1].trim();
  confirmedCustomerChatId = orderConfirmedMatch[2].trim();
}

// Extract [PAYMENT_CONFIRMED: ...]
const paymentConfirmedMatch = outputRaw.match(/\[PAYMENT_CONFIRMED:\s*([\w-]+)\s*(?:\|\s*(\d+))?\]/);
if (paymentConfirmedMatch) {
  paymentConfirmed = true;
  paymentOrderNumber = paymentConfirmedMatch[1].trim();
  if (paymentConfirmedMatch[2]) {
    confirmedCustomerChatId = paymentConfirmedMatch[2].trim();
  }
}

// Extract [BROADCAST: ...]
const broadcastMatch = outputRaw.match(/\[BROADCAST:\s*([\s\S]*?)\]/);
if (broadcastMatch) {
  broadcastMessage = broadcastMatch[1].trim().substring(0, 1000);
}

// Extract legacy generation tags
const imageGenMatch    = outputRaw.match(/\[IMAGE_GEN:\s*(.*?)\]/s);
const videoGenMatch    = outputRaw.match(/\[VIDEO_GEN:\s*(.*?)\]/s);
const image2imageMatch = outputRaw.match(/\[IMAGE2IMAGE:\s*(.*?)\]/s);
const image2videoMatch = outputRaw.match(/\[IMAGE2VIDEO:\s*(.*?)\]/s);

if (imageGenMatch) {
  response_type = 'image'; genPrompt = imageGenMatch[1].trim(); genMode = 'text_to_image'; mediaType = 'image';
} else if (videoGenMatch) {
  response_type = 'video'; genPrompt = videoGenMatch[1].trim(); genMode = 'text_to_video'; mediaType = 'video';
} else if (image2imageMatch) {
  response_type = 'image'; genPrompt = image2imageMatch[1].trim(); genMode = 'image_to_image'; mediaType = 'image';
} else if (image2videoMatch) {
  response_type = 'video'; genPrompt = image2videoMatch[1].trim(); genMode = 'image_to_video'; mediaType = 'video';
}

// Check for FAL_MEDIA_REQUEST
const hasFalRequest = outputRaw.includes('[FAL_MEDIA_REQUEST:');

if (hasFalRequest) {
  response_type = 'image';

  const falStart = outputRaw.indexOf('[FAL_MEDIA_REQUEST:');
  if (falStart !== -1) {
    const braceStart = outputRaw.indexOf('{', falStart);
    if (braceStart !== -1) {
      let braceCount = 0;
      let braceEnd = -1;
      let inString = false;
      let escapeNext = false;

      for (let i = braceStart; i < outputRaw.length; i++) {
        const char = outputRaw[i];
        if (escapeNext) { escapeNext = false; continue; }
        if (char === '\\') { escapeNext = true; continue; }
        if (char === '"') { inString = !inString; continue; }
        if (!inString) {
          if (char === '{') braceCount++;
          if (char === '}') {
            braceCount--;
            if (braceCount === 0) { braceEnd = i; break; }
          }
        }
      }

      if (braceEnd !== -1) {
        const falContent = outputRaw.substring(braceStart, braceEnd + 1);

        const modeMatch   = falContent.match(/"generation_mode"\s*:\s*"([^"]+)"/);
        if (modeMatch) genMode = modeMatch[1];

        const promptMatch = falContent.match(/"prompt"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        if (promptMatch) genPrompt = promptMatch[1].replace(/\\"/g, '"').replace(/\\\\/g, '\\');

        if (genMode === 'text_to_image' || genMode === 'image_to_image') {
          response_type = 'image'; mediaType = 'image';
        } else if (genMode === 'text_to_video' || genMode === 'image_to_video') {
          response_type = 'video'; mediaType = 'video';
        }
      }
    }
  }

  if (!bufferMessage && genMode) bufferMessage = 'Gimme a sec...';
  if (!caption && genMode) caption = 'Here you go!';

  return {
    json: {
      output: outputRaw,
      response_type,
      message_type_in: incomingData.message_type || 'text',
      gen_prompt: genPrompt,
      gen_mode: genMode,
      buffer_message: bufferMessage,
      caption,
      has_order_confirmed: hasOrderConfirmed,
      confirmed_order_number: confirmedOrderNumber,
      confirmed_customer_chat_id: confirmedCustomerChatId,
      payment_confirmed: paymentConfirmed,
      payment_order_number: paymentOrderNumber,
      broadcast_message: broadcastMessage,
    }
  };
}

// ── Non-media responses — clean output ──────────────────────
let cleanOutput = outputRaw;
cleanOutput = cleanOutput
  .replace(/\[BUFFER:.*?\]/s, '')
  .replace(/\[CAPTION:.*?\]/s, '')
  .replace(/\[ORDER_CONFIRMED:.*?\]/s, '')
  .replace(/\[PAYMENT_CONFIRMED:.*?\]/s, '')
  .replace(/\[BROADCAST:[\s\S]*?\]/g, '')
  .trim();

if (!cleanOutput || cleanOutput === '') {
  cleanOutput = 'Done!';
}

return {
  json: {
    output: cleanOutput.trim(),
    response_type,
    message_type_in: incomingData.message_type || 'text',
    gen_prompt: null,
    gen_mode: null,
    buffer_message: null,
    caption: null,
    has_order_confirmed: hasOrderConfirmed,
    confirmed_order_number: confirmedOrderNumber,
    confirmed_customer_chat_id: confirmedCustomerChatId,
    payment_confirmed: paymentConfirmed,
    payment_order_number: paymentOrderNumber,
    broadcast_message: broadcastMessage,
  }
};
